/**
 * Font registry for the Theme Studio font picker.
 *
 * ALL families are SELF-HOSTED (no CDN):
 *   - The bundled defaults (Inter / IBM Plex Arabic / JetBrains Mono) via next/font/local.
 *   - A curated menu of Google families self-hosted as woff2 under
 *     /public/fonts/web (generated by scripts/fetch-local-fonts.sh) and declared
 *     in /public/fonts/web-fonts.css.
 *   - The 29LT PBL brand fonts under /public/fonts/brand, declared in
 *     /public/fonts/brand-fonts.css.
 * The stylesheets are linked from src/app/layout.tsx.
 *
 * Picking a font writes its `family` to the `--font-sans` AND `--font-arabic`
 * theme tokens (the values the whole app consumes). Latin-only families carry
 * an Arabic fallback in the stack so Arabic text still renders well. The
 * "System default" option clears those tokens (use the bundled fonts).
 */

export type FontCategory = "default" | "brand" | "arabic" | "sans" | "serif"

export interface FontOption {
  /** Stable id stored as the picker selection. */
  id: string
  /** English display label. */
  label: string
  /** Native/Arabic display label. */
  labelAr: string
  /** Grouping for the picker. */
  category: FontCategory
  /**
   * CSS font-family stack written to --font-sans / --font-arabic.
   * Empty string = clear the override (use the bundled default fonts).
   */
  family: string
  /** Short sample shown in the picker (Latin + Arabic). */
  sample: string
}

/** Sentinel id for "use the app's bundled default fonts". */
export const DEFAULT_FONT_ID = "default"

/** Arabic fallback appended to Latin-only families so Arabic copy still renders. */
const AR_FALLBACK = '"Noto Sans Arabic", "IBM Plex Sans Arabic", system-ui, sans-serif'
const SAMPLE = "Aa Bb 123 — أبجد هوز"

const arabic = (face: string): string => `"${face}", system-ui, sans-serif`
const sans = (face: string): string => `"${face}", ${AR_FALLBACK}`
const serif = (face: string): string => `"${face}", "Amiri", Georgia, serif`

