/** Human labels for the picker's category groups. */
export const FONT_CATEGORY_LABELS: Record<FontCategory, string> = {
  default: "Default",
  brand: "PBL brand (29LT)",
  arabic: "Arabic",
  sans: "Sans-serif",
  serif: "Serif & display",
}

/** Theme tokens the font picker writes (kept in sync app-wide). */
export const FONT_TOKEN_KEYS = ["--font-sans", "--font-arabic"] as const

/**
 * Resolve the currently-selected font id from a token map by matching the
 * `--font-sans` value against the registry. Falls back to DEFAULT_FONT_ID when
 * the token is unset, or "custom" for a hand-edited stack we don't recognise.
 */
export function fontIdFromTokens(tokens: Record<string, string>): string {
  const current = tokens["--font-sans"]?.trim()
  if (!current) return DEFAULT_FONT_ID
  const match = FONT_OPTIONS.find(o => o.family && o.family === current)
  return match?.id ?? "custom"
}
